import React, { useEffect, useState } from 'react';
import '../pageStyles/Products.css';
import PageTitle from '../components/PageTitle';
import Navbar from '../components/Navbar';
import { useDispatch, useSelector } from 'react-redux';
import Footer from '../components/Footer';
import { getProduct, removeErrors } from '../features/products/productSlice';
import { toast } from 'react-toastify';
import Product from '../components/Product';
import { useLocation, useNavigate, Link } from 'react-router-dom';
import Loader from '../components/Loader';
import Pagination from '../components/Pagination';

function Products() {
  // Redux state
  const { loading, error, products, productCount } = useSelector(state => state.product);
  const dispatch = useDispatch();
  const location = useLocation();
  const navigate = useNavigate();

  // URL params
  const searchParams = new URLSearchParams(location.search);
  const keyword = searchParams.get("keyword");
  const categoryFromURL = searchParams.get("category");
  const pageFromURL = parseInt(searchParams.get("page"), 10) || 1;

  // Component state
  const [currentPage, setCurrentPage] = useState(pageFromURL);
  const [isMobileDrawerOpen, setIsMobileDrawerOpen] = useState(false);

  // Filter states
  const [selectedCategories, setSelectedCategories] = useState(categoryFromURL ? [categoryFromURL] : []);
  const [priceRange, setPriceRange] = useState({ min: 0, max: 30000000 }); // UI input values (VND)
  const [appliedPrice, setAppliedPrice] = useState(null); // Actual filter sent to API
  const [priceError, setPriceError] = useState(''); // Validation error message
  const [selectedRating, setSelectedRating] = useState(null);
  const [inStockOnly, setInStockOnly] = useState(false);
  const [sortBy, setSortBy] = useState('newest');

  // Available options
  const categories = ["Quß║ºn ├ío", "Phß╗Ñ kiß╗çn", "Gi├áy d├⌐p", "T├║i x├ích", "─Éß╗ông hß╗ô", "M┼⌐", "Kh├íc"];
  const ratings = [5, 4, 3, 2, 1];
  const PRICE_MIN = 0;
  const PRICE_MAX = 30000000; // 30 triß╗çu VND

  // Preset price ranges (Shopee-style chips)
  const pricePresets = [
    { label: 'D╞░ß╗¢i 100k', min: 0, max: 100000 },
    { label: '100k - 500k', min: 100000, max: 500000 },
    { label: '500k - 1tr', min: 500000, max: 1000000 },
    { label: 'Tr├¬n 1tr', min: 1000000, max: PRICE_MAX },
  ];

  // Helper: format gi├í VND
  const formatVND = (value) => value.toLocaleString('vi-VN') + 'Γé½';

  // Close drawer when route changes
  useEffect(() => {
    setIsMobileDrawerOpen(false);
  }, [location]);

  // Handle body scroll lock
  useEffect(() => {
    if (isMobileDrawerOpen) {
      document.body.classList.add('no-scroll');
    } else {
      document.body.classList.remove('no-scroll');
    }
    return () => document.body.classList.remove('no-scroll');
  }, [isMobileDrawerOpen]);

  // Fetch products ΓÇö chß╗ë gß╗ìi khi appliedPrice thay ─æß╗òi (nhß║Ñn ├üp dß╗Ñng / click chip)
  useEffect(() => {
    const category = selectedCategories.length > 0 ? selectedCategories[0] : null;

    dispatch(getProduct({
      keyword,
      page: currentPage,
      category,
      price: appliedPrice,
      sort: sortBy,
      ratings: selectedRating
        ? { gte: selectedRating, lt: selectedRating + 1 }
        : null,
      inStock: inStockOnly,
    }));
  }, [dispatch, currentPage, selectedCategories, keyword, appliedPrice, sortBy, selectedRating, inStockOnly]);

  // Handle errors
  useEffect(() => {
    if (error) {
      toast.error(error.message, { position: 'top-center', autoClose: 3000 });
      dispatch(removeErrors());
    }
  }, [dispatch, error]);

  // Pagination handler
  const handlePageChange = (page) => {
    if (page !== currentPage) {
      setCurrentPage(page);
      const newSearchParams = new URLSearchParams(location.search);
      if (page === 1) {
        newSearchParams.delete('page');
      } else {
        newSearchParams.set('page', page);
      }
      navigate(`?${newSearchParams.toString()}`);
    }
  };

  // Category filter handler
  const handleCategoryToggle = (category) => {
    setSelectedCategories(prev => {
      if (prev.includes(category)) {
        return prev.filter(c => c !== category);
      } else {
        // For now, only allow single category selection (backend limitation)
        return [category];
      }
    });
    setCurrentPage(1);
    const newSearchParams = new URLSearchParams(location.search);
    newSearchParams.delete('page');
    if (selectedCategories.includes(category)) {
      newSearchParams.delete('category');
    } else {
      newSearchParams.set('category', category);
    }
    navigate(`?${newSearchParams.toString()}`);
  };

  // Price input handler ΓÇö validate tr╞░ß╗¢c khi apply
  const handleApplyPrice = () => {
    if (priceRange.min > 0 && priceRange.max > 0 && priceRange.min > priceRange.max) {
      setPriceError('Khoß║úng gi├í kh├┤ng hß╗úp lß╗ç');
      return;
    }
    setPriceError('');
    // Tß║ío filter thß╗▒c sß╗▒ ΓåÆ trigger useEffect gß╗ìi API
    const newPrice =
      (priceRange.min > PRICE_MIN || priceRange.max < PRICE_MAX)
        ? { gte: priceRange.min, lte: priceRange.max }
        : null;
    setAppliedPrice(newPrice);
    setCurrentPage(1);
  };

  // Preset chip click handler
  const handlePresetClick = (preset) => {
    setPriceRange({ min: preset.min, max: preset.max });
    // Chip = ├íp dß╗Ñng ngay, gß╗¡i API lu├┤n
    setAppliedPrice({ gte: preset.min, lte: preset.max });
    setPriceError('');
    setCurrentPage(1);
  };

  // Rating filter handler
  const handleRatingChange = (rating) => {
    setSelectedRating(rating === selectedRating ? null : rating);
    setCurrentPage(1);
  };


  // Sort handler
  const handleSortChange = (e) => {
    setSortBy(e.target.value);
    setCurrentPage(1);
  };

  // Clear all filters
  const handleClearAll = () => {
    setSelectedCategories([]);
    setPriceRange({ min: PRICE_MIN, max: PRICE_MAX });
    setAppliedPrice(null);
    setSelectedRating(null);
    setInStockOnly(false);
    setSortBy('newest');
    setCurrentPage(1);
    navigate('/products');
  };


  // Calculate active filter count
  const activeFilterCount =
    selectedCategories.length +
    (appliedPrice ? 1 : 0) +
    (selectedRating ? 1 : 0) +
    (inStockOnly ? 1 : 0);

  // Render filter section (reusable for desktop and mobile)
  const renderFilters = (isMobile = false) => {
    const renderCategoryLink = (label, filterValue) => {
      const isActive = selectedCategories.includes(filterValue);
      return (
        <button
          className={`category-link relative text-left inline-block transition-colors hover:text-black ${isActive ? 'font-medium text-black' : ''}`}
          onClick={(e) => { e.preventDefault(); handleCategoryToggle(filterValue); }}
        >
          {label}
        </button>
      );
    };

    return (
    <>
      <style>
        {`
          @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');
          .heading-serif { font-family: 'Playfair+Display', serif; }
          .category-link::after { content: ''; position: absolute; width: 0; height: 1px; bottom: -2px; left: 0; background-color: currentColor; transition: width 0.3s ease; }
          .category-link:hover::after { width: 100%; }
        `}
      </style>

      {/* Category Filter */}
      <aside className="w-full shrink-0" data-purpose="category-sidebar">
        <h2 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-6">Kh├ím Ph├í Danh Mß╗Ñc</h2>
        <div className="space-y-8">
          {/* ├üo Section */}
          <div>
            <h3 className="text-sm font-semibold mb-4 flex items-center justify-between group cursor-pointer">
              ├üO
            </h3>
            <ul className="space-y-2 pl-3 border-l border-gray-100 text-sm text-gray-600 mb-8">
              <li>{renderCategoryLink('├üo thun', '├üo thun')}</li>
              <li>{renderCategoryLink('├üo s╞í mi', '├üo s╞í mi')}</li>
              <li>{renderCategoryLink('├üo hoodie', '├üo hoodie')}</li>
              <li>{renderCategoryLink('├üo kho├íc', '├üo kho├íc')}</li>
              <li>{renderCategoryLink('├üo polo', '├üo polo')}</li>
            </ul>
          </div>
          {/* Quß║ºn Section */}
          <div>
            <h3 className="text-sm font-semibold mb-4 flex items-center justify-between group cursor-pointer">
              QUß║ªN
            </h3>
            <ul className="space-y-2 pl-3 border-l border-gray-100 text-sm text-gray-600 mb-8">
              <li>{renderCategoryLink('Quß║ºn jean', 'Quß║ºn jean')}</li>
              <li>{renderCategoryLink('Quß║ºn short', 'Quß║ºn short')}</li>
              <li>{renderCategoryLink('Quß║ºn kaki', 'Quß║ºn kaki')}</li>
              <li>{renderCategoryLink('Quß║ºn jogger', 'Quß║ºn jogger')}</li>
              <li>{renderCategoryLink('Quß║ºn ß╗æng rß╗Öng', 'Quß║ºn ß╗æng rß╗Öng')}</li>
            </ul>
          </div>
          {/* V├íy Section */}
          <div>
            <h3 className="text-sm font-semibold mb-4 flex items-center justify-between group cursor-pointer">
              V├üY
            </h3>
            <ul className="space-y-2 pl-3 border-l border-gray-100 text-sm text-gray-600 mb-8">
              <li>{renderCategoryLink('V├íy ngß║»n', 'V├íy ngß║»n')}</li>
              <li>{renderCategoryLink('V├íy d├ái', 'V├íy d├ái')}</li>
              <li>{renderCategoryLink('V├íy body', 'V├íy body')}</li>
            </ul>
          </div>
          {/* Phß╗Ñ kiß╗çn Section */}
          <div>
            <h3 className="text-sm font-semibold mb-4 flex items-center justify-between group cursor-pointer">
              PHß╗ñ KIß╗åN
              <span className="text-[10px] text-gray-400">08</span>
            </h3>
            <ul className="space-y-6 pl-1 text-sm text-gray-600">
              <li>
                <span className="block font-medium text-black mb-2">Gi├áy d├⌐p</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('Sneaker', 'Sneaker')}</li>
                  <li>{renderCategoryLink('Sandal', 'Sandal')}</li>
                  <li>{renderCategoryLink('D├⌐p', 'D├⌐p')}</li>
                  <li>{renderCategoryLink('Gi├áy cao g├│t', 'Gi├áy cao g├│t')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">T├║i & Balo</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('T├║i tote', 'T├║i tote')}</li>
                  <li>{renderCategoryLink('T├║i ─æeo ch├⌐o', 'T├║i ─æeo ch├⌐o')}</li>
                  <li>{renderCategoryLink('T├║i mini', 'T├║i mini')}</li>
                  <li>{renderCategoryLink('Balo', 'Balo')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">M┼⌐</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('M┼⌐ l╞░ß╗íi trai', 'M┼⌐ l╞░ß╗íi trai')}</li>
                  <li>{renderCategoryLink('M┼⌐ bucket', 'M┼⌐ bucket')}</li>
                  <li>{renderCategoryLink('M┼⌐ len', 'M┼⌐ len')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">K├¡nh</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('K├¡nh m├ít', 'K├¡nh m├ít')}</li>
                  <li>{renderCategoryLink('K├¡nh thß╗¥i trang', 'K├¡nh thß╗¥i trang')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">V├¡</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('V├¡ da', 'V├¡ da')}</li>
                  <li>{renderCategoryLink('V├¡ mini', 'V├¡ mini')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">Thß║»t l╞░ng</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('Thß║»t l╞░ng da', 'Thß║»t l╞░ng da')}</li>
                  <li>{renderCategoryLink('Thß║»t l╞░ng vß║úi', 'Thß║»t l╞░ng vß║úi')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">Trang sß╗⌐c</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('V├▓ng tay', 'V├▓ng tay')}</li>
                  <li>{renderCategoryLink('D├óy chuyß╗ün', 'D├óy chuyß╗ün')}</li>
                  <li>{renderCategoryLink('Nhß║½n', 'Nhß║½n')}</li>
                  <li>{renderCategoryLink('B├┤ng tai', 'B├┤ng tai')}</li>
                </ul>
              </li>
              <li>
                <span className="block font-medium text-black mb-2">Kh─ân</span>
                <ul className="pl-3 space-y-2 border-l border-gray-100">
                  <li>{renderCategoryLink('Kh─ân lß╗Ña', 'Kh─ân lß╗Ña')}</li>
                  <li>{renderCategoryLink('Kh─ân len', 'Kh─ân len')}</li>
                </ul>
              </li>
            </ul>
          </div>
        </div>
      </aside>

      {/* Price Range ΓÇö Shopee-style Input Fields */}
      <div className="filter-section">
        <h3>Khoß║úng gi├í</h3>

        {/* Min/Max Input Row */}
        <div className="price-inputs-row">
          <div className="price-input-wrapper">
            <input
              type="number"
              className="price-input"
              placeholder="Tß╗½ Γé½"
              value={priceRange.min || ''}
              onChange={(e) => {
                const value = e.target.value === '' ? 0 : Number(e.target.value);
                setPriceRange({ ...priceRange, min: value });
                setPriceError('');
              }}
            />
          </div>
          <span className="price-divider">ΓÇö</span>
          <div className="price-input-wrapper">
            <input
              type="number"
              className="price-input"
              placeholder="─Éß║┐n Γé½"
              value={priceRange.max >= PRICE_MAX ? '' : priceRange.max}
              onChange={(e) => {
                const value = e.target.value === '' ? PRICE_MAX : Number(e.target.value);
                setPriceRange({ ...priceRange, max: value });
                setPriceError('');
              }}
            />
          </div>
        </div>

        {/* Error Message */}
        {priceError && (
          <p className="price-error">{priceError}</p>
        )}

        {/* Apply Button */}
        <button className="price-apply-btn" onClick={handleApplyPrice}>
          ├üp dß╗Ñng
        </button>

        {/* Preset Chips */}
        <div className="price-presets">
          <p className="price-presets-label">Gß╗úi ├╜:</p>
          <div className="price-presets-chips">
            {pricePresets.map((preset, index) => (
              <button
                key={index}
                className={`preset-chip ${priceRange.min === preset.min && priceRange.max === preset.max ? 'active' : ''
                  }`}
                onClick={() => handlePresetClick(preset)}
              >
                {preset.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Rating Filter */}
      <div className="filter-section">
        <h3>─É├ính gi├í</h3>
        <div className="filter-options">
          {ratings.map((rating) => (
            <div key={rating} className="filter-option">
              <input
                type="checkbox"
                id={`${isMobile ? 'mobile-' : ''}rating-${rating}`}
                className="custom-checkbox"
                checked={selectedRating === rating}
                onChange={() => handleRatingChange(rating)}
              />
              <label htmlFor={`${isMobile ? 'mobile-' : ''}rating-${rating}`} className="rating-option">
                <span className="rating-stars">
                  {'Γÿà'.repeat(rating)}{'Γÿå'.repeat(5 - rating)}
                </span>

              </label>
            </div>
          ))}
        </div>

      </div>

      {/* Stock Filter */}
      
    </>
  );
  };

  return (
    <>
      <PageTitle title="Tß║Ñt cß║ú sß║ún phß║⌐m" />
      <Navbar />

      {/* Breadcrumb */}
      {/* <div className="breadcrumb-section">
        <div className="breadcrumb-container">
          <div className="breadcrumb">
            <Link to="/">Trang chß╗º</Link>
            <span>/</span>
            <span className="current">
              {keyword ? `T├¼m kiß║┐m: "${keyword}"` : 'Sß║ún phß║⌐m'}
            </span>
          </div>
        </div>
      </div> */}

      {/* Mobile Filter Button */}
      <div className="mobile-filter-bar">
        <div className="mobile-filter-container">
          <button
            className="mobile-filter-btn"
            onClick={() => setIsMobileDrawerOpen(true)}
          >
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M2.5 5.83333H17.5M5.83333 10H14.1667M8.33333 14.1667H11.6667" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
            <span>Bß╗Ö lß╗ìc</span>
            {activeFilterCount > 0 && (
              <span className="filter-count-badge">{activeFilterCount}</span>
            )}
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="flex flex-col md:flex-row gap-12">
          
          {/* Desktop Sidebar */}
          <div className="hidden md:block w-64 min-w-[16rem]">
            {renderFilters(false)}
          </div>

          {/* Mobile Drawer Overlay */}
          <div className={`mobile-drawer-overlay ${isMobileDrawerOpen ? '' : 'hidden'}`}>
            <div
              className={`drawer-backdrop ${isMobileDrawerOpen ? 'show' : ''}`}
              onClick={() => setIsMobileDrawerOpen(false)}
            />
            <div className={`mobile-drawer ${isMobileDrawerOpen ? 'open' : ''} w-3/4 max-w-sm bg-white p-6 h-full overflow-y-auto`}>
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-lg font-bold">Bß╗Ö lß╗ìc</h2>
                <button
                  className="text-2xl"
                  onClick={() => setIsMobileDrawerOpen(false)}
                >
                  ├ù
                </button>
              </div>
              {renderFilters(true)}
              <div className="mt-8 pt-4 border-t flex gap-4">
                <button className="flex-1 py-2 outline outline-1 outline-gray-300" onClick={handleClearAll}>
                  X├│a tß║Ñt cß║ú
                </button>
                <button
                  className="flex-1 py-2 bg-black text-white"
                  onClick={() => setIsMobileDrawerOpen(false)}
                >
                  ├üp dß╗Ñng
                </button>
              </div>
            </div>
          </div>

          {/* Products Area */}
          <section className="flex-1" data-purpose="product-display">
            {/* Filter/Sort Bar */}
            <div className="flex flex-wrap items-center justify-between border-b border-gray-200 pb-6 mb-8 text-sm">
              <div className="flex space-x-6 items-center">
                <button 
                  className="md:hidden flex items-center space-x-2 text-gray-600 hover:text-black"
                  onClick={() => setIsMobileDrawerOpen(true)}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5"></path></svg>
                  <span>Bß╗Ö lß╗ìc {activeFilterCount > 0 && `(${activeFilterCount})`}</span>
                </button>
                <span className="hidden md:inline text-gray-300">|</span>
                <span className="text-gray-500">{productCount} Sß║ún phß║⌐m</span>
              </div>
              <div className="flex items-center space-x-2 mt-4 sm:mt-0">
                <span className="text-gray-500">Sß║»p xß║┐p theo:</span>
                <select 
                  className="border-none bg-transparent focus:ring-0 text-sm font-medium py-0 pr-8 cursor-pointer"
                  value={sortBy}
                  onChange={handleSortChange}
                >
                  <option value="newest">Mß╗¢i nhß║Ñt</option>
                  <option value="price_asc">Gi├í: Thß║Ñp ─æß║┐n Cao</option>
                  <option value="price_desc">Gi├í: Cao ─æß║┐n Thß║Ñp</option>
                  <option value="rating_desc">Phß╗ò biß║┐n nhß║Ñt</option>
                </select>
              </div>
            </div>

              {/* Loading State */}
              {loading && (
                <div className="loading-skeleton">
                  {[1, 2, 3, 4, 5, 6].map((i) => (
                    <div key={i} className="skeleton-card" />
                  ))}
                </div>
              )}

              {/* Empty State */}
              {!loading && products.length === 0 && (
                <div className="empty-state py-12 flex flex-col items-center justify-center text-center">
                  <div className="text-4xl mb-4">≡ƒæù</div>
                  <h3 className="text-xl font-medium mb-2">Kh├┤ng t├¼m thß║Ñy sß║ún phß║⌐m</h3>
                  <p className="text-gray-500 mb-6">
                    Thß╗¡ ─æiß╗üu chß╗ënh bß╗Ö lß╗ìc hoß║╖c tß╗½ kh├│a t├¼m kiß║┐m
                  </p>
                  <button className="px-6 py-2 bg-black text-white rounded-md hover:bg-gray-800 transition-colors" onClick={handleClearAll}>
                    X├│a bß╗Ö lß╗ìc
                  </button>
                </div>
              )}

              {/* Products Grid */}
              {!loading && products.length > 0 && (
                <>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-6 gap-y-12">
                    {products.map((product) => (
                      <Product key={product._id} product={product} />
                    ))}
                  </div>

                  {/* Pagination */}
                  <div className="mt-20 flex justify-center border-t border-gray-100 pt-10">
                    <Pagination
                      currentPage={currentPage}
                      onPageChange={handlePageChange}
                    />
                  </div>
                </>
              )}
          </section>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Products;
